// 每日词库大小
export const WORDS_PER_DAY = 50;

// 获取第 n 天的词库（dayIndex 从 0 开始）
export function getDailyWords(dayIndex: number): Word[] {
  const start = dayIndex * WORDS_PER_DAY;
  const end = start + WORDS_PER_DAY;
  return vocabulary.slice(start, end);
}

// 获取总天数
export const TOTAL_DAYS = Math.ceil(vocabulary.length / WORDS_PER_DAY);
